  ('customs-39f5e973-moex-00027', 'customs-39f5e973', 'customs-39f5e973-moex-114-1400d907', 'sub-customs-39f5e973-01', NULL, 'single_choice', '①asidefrom ②basedon ③inspiteof ④onbehalfof', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:19+00:00", "source_pdf_sha1": "646867c18d04", "answer_pdf_sha1": "0f81576174b9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "107", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "外國文(英文)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "customs", "civil_category": "資訊處理"}'::jsonb, NULL),
  ('customs-39f5e973-moex-00028', 'customs-39f5e973', 'customs-39f5e973-moex-114-804ba136', 'sub-customs-39f5e973-02', NULL, 'essay', '假設某個銀行需要管理顧客借款的資料，而定義了三個表格，其中
CUSTOMER表格記錄顧客基本資料，包含身分證字號（ID）、姓名（Name）、
地址（Address）和連絡電話（Telephone）；LOAN 表格記錄每筆借款的
基本資料，包含借款編號（LoanNO）、借款金額（Amount）和辦理借款
的銀行分行名稱（Branch）；BORROWER表格則記錄借貸關係，包含借
款顧客（ID）、借款編號（LoanNO）和借貸成立日期（Date）。所有屬性
除了「借款金額」為數字型態之外，其餘皆為字串型態。此三個表格的綱
要簡列如下，且每個表格的主鍵以底線標註：
CUSTOMER（ID,Name, Address, Telephone）
LOAN（LoanNO, Amount,Branch）
BORROWER（ID,LoanNO, Date）
請利用 SQL查詢指令，分別回答下列問題：（每小題 10分，共 30 分）
找出那些顧客曾經在此銀行的“忠孝東路”分行辦理借款，列出其顧客身
分證字號、借款編號和借款金額。
找出每家分行的最大借款金額。
找出住在臺北市且借款超過 3次以上的顧客身分證字號。', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:19+00:00", "source_pdf_sha1": "d8479f39b69b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "107", "s": "1208", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "資料庫應用", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "資訊處理"}'::jsonb, NULL),
  ('customs-39f5e973-moex-00029', 'customs-39f5e973', 'customs-39f5e973-moex-114-804ba136', 'sub-customs-39f5e973-02', NULL, 'essay', '假設在關聯式資料庫系統中，資料庫管理者（DBA）定義了一個 MEMBER
表格，並以三個字串型態的屬性記錄會員的基本資料，包含：編號（ID）、
姓名（Name）、電話號碼（Telephone）。經統計分析發現此系統的使用
者經常利用會員姓名查詢其電話號碼，如下列的範例 SQL查詢句所示：
select TelephonefromMEMBER whereName = ‘Wu’;
請問此資料庫管理者應該替那個或那些屬性建立索引（Index），以提升資
料庫系統的查詢處理效率？進一步以範例資料畫出此索引的樹狀結構，並
詳加說明此結構具有何種特性，可協助達到提升效率的目的。（20 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:19+00:00", "source_pdf_sha1": "d8479f39b69b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "107", "s": "1208", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "資料庫應用", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "資訊處理"}'::jsonb, NULL),
  ('customs-39f5e973-moex-00030', 'customs-39f5e973', 'customs-39f5e973-moex-114-804ba136', 'sub-customs-39f5e973-02', NULL, 'essay', '假設一家零售商希望對顧客的購買行為進行資料分析，而考慮是否在現有
的交易處理系統（Transaction Processing System）之外，另外再建立一個
資料倉儲（Data Warehouse）。請根據不同面向說明此兩種系統的差別，
包含資料來源多寡或資料時間特性、綱要（Schema）的設計理念（譬如是
強調正規化還是處理效率）、較常使用的 SQL指令（譬如：新增、刪除、
修改、查詢）等。並根據上述比較的結果，建議此廠商分開建立成兩個系
統或整合成一個系統。（30分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:19+00:00", "source_pdf_sha1": "d8479f39b69b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "107", "s": "1208", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "資料庫應用", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "資訊處理"}'::jsonb, NULL),
  ('customs-39f5e973-moex-00031', 'customs-39f5e973', 'customs-39f5e973-moex-114-804ba136', 'sub-customs-39f5e973-02', NULL, 'essay', 'JSON（JavaScript Object Notation）格式經常被用來表示半結構化資料
（Semi-StructuredData）。假設我們要建立多筆顧客的資料，其中顧客編
號（No）和姓名（Name）為字串型態，而子女（Children）則為數個字串
組合而成的陣列。兩個顧客的範例資料如下表所示：
No Name Children
1 張三 John,Mary
2 李四 John,Tom, Sandy
請將上述內容以一個集合（collection）內含兩個 JSON文件（document）
表示，並讓一個顧客對應到一個 JSON文件。（20分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:19+00:00", "source_pdf_sha1": "d8479f39b69b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "107", "s": "1208", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "資料庫應用", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "資訊處理"}'::jsonb, NULL)
